import jwt

def decode_jwt(token, secret_key, algorithms=["HS256"]):
    try:
        decoded = jwt.decode(token, secret_key, algorithms=algorithms, options={"verify_signature": False})
        return decoded
    except jwt.DecodeError as e:
        return f"Decode Error: {str(e)}"
    except jwt.InvalidTokenError as e:
        return f"Invalid Token Error: {str(e)}"

